// htmx placeholder - replace with real htmx 2.0.x from https://unpkg.com/htmx.org@2/dist/htmx.min.js
// This is a minimal stub that provides the htmx API surface used by this app.
(function() {
    "use strict";
    var htmx = {
        version: "2.0.0-placeholder",
        onLoad: function(callback) {
            document.addEventListener("DOMContentLoaded", function() { callback(document.body); });
        },
        on: function(elt, evt, handler) {
            if (typeof elt === "string") { handler = evt; evt = elt; elt = document; }
            elt.addEventListener(evt, handler);
        },
        trigger: function(elt, name, detail) {
            elt.dispatchEvent(new CustomEvent(name, { detail: detail, bubbles: true }));
        },
        ajax: function(verb, url, options) {
            var target = options.target || options;
            fetch(url, { method: verb })
                .then(function(r) { return r.text(); })
                .then(function(html) {
                    if (typeof target === "string") target = document.querySelector(target);
                    if (target) {
                        target.innerHTML = html;
                        document.dispatchEvent(new CustomEvent("htmx:afterSwap", { detail: { target: target } }));
                    }
                });
        },
        process: function(elt) {
            // Process htmx attributes on an element
            elt.querySelectorAll("[hx-get]").forEach(function(el) {
                if (el._htmxProcessed) return;
                el._htmxProcessed = true;
                var url = el.getAttribute("hx-get");
                var trigger = el.getAttribute("hx-trigger") || "click";
                var targetSel = el.getAttribute("hx-target");
                var includeSel = el.getAttribute("hx-include");
                var indicator = el.getAttribute("hx-indicator");

                var eventName = trigger.split(" ")[0].split(",")[0];
                if (eventName === "keyup" || eventName === "input" || eventName === "search") {
                    var delay = 0;
                    var delayMatch = trigger.match(/delay:(\d+)ms/);
                    if (delayMatch) delay = parseInt(delayMatch[1], 10);

                    var timer = null;
                    el.addEventListener(eventName, function() {
                        clearTimeout(timer);
                        timer = setTimeout(function() { doRequest(el, url, targetSel, includeSel, indicator); }, delay);
                    });
                    // Also handle "search" event for type="search" clear button
                    if (eventName === "keyup" && trigger.indexOf("search") !== -1) {
                        el.addEventListener("search", function() {
                            clearTimeout(timer);
                            doRequest(el, url, targetSel, includeSel, indicator);
                        });
                    }
                } else if (eventName === "load") {
                    // Fire immediately when the element is processed
                    doRequest(el, url, targetSel, includeSel, indicator);
                } else if (eventName === "change") {
                    el.addEventListener("change", function() {
                        doRequest(el, url, targetSel, includeSel, indicator);
                    });
                } else {
                    el.addEventListener("click", function(e) {
                        e.preventDefault();
                        doRequest(el, url, targetSel, includeSel, indicator);
                    });
                }
            });
        }
    };

    function doRequest(el, _url, targetSel, includeSel, indicatorSel) {
        // Re-read hx-get at request time so dynamic attribute changes take effect
        var url = el.getAttribute("hx-get") || _url;
        var target = targetSel ? document.querySelector(targetSel) : el;
        var params = new URLSearchParams();

        // Include the element's own value if it has a name
        if (el.name && el.value !== undefined) {
            params.set(el.name, el.value);
        }

        // Include additional elements
        if (includeSel) {
            document.querySelectorAll(includeSel).forEach(function(inc) {
                if (inc.name && inc.value !== undefined) {
                    params.set(inc.name, inc.value);
                }
            });
        }

        var fullUrl = url + (params.toString() ? "?" + params.toString() : "");

        // Show indicator
        var indicator = indicatorSel ? document.querySelector(indicatorSel) : null;
        if (el.closest) {
            var parent = el.closest(".htmx-indicator") ? null : el;
            if (parent) parent.classList.add("htmx-request");
        }
        if (indicator) indicator.classList.add("htmx-request");

        fetch(fullUrl)
            .then(function(r) { return r.text(); })
            .then(function(html) {
                if (target) {
                    target.innerHTML = html;
                    htmx.process(target);
                }
                document.dispatchEvent(new CustomEvent("htmx:afterSwap", { detail: { target: target } }));
            })
            .finally(function() {
                if (el.closest) {
                    var parent2 = el;
                    if (parent2) parent2.classList.remove("htmx-request");
                }
                if (indicator) indicator.classList.remove("htmx-request");
            });
    }

    // Auto-process on load
    document.addEventListener("DOMContentLoaded", function() {
        htmx.process(document.body);
    });

    window.htmx = htmx;
})();
